var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS006M0713-01: <color=#ffd34c>【부록-004】 관계자 증언</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. FS006M0713-01：<color=#ffd34c>【付録-004】関係者の証言</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS006M0713-01: <color=#ffd34c>【Appendix-004】 Contact Testimony</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS006M0713-01: <color=#ffd34c>【附錄-004】 相關人士證言</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......소, 소개팅 알선이요?","JPN":"……ご、合コンの斡旋ですか？","ENG":"D-did I ask him to set up a blind date?","TWN":"……安、安排聯誼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그, 그런 터무니없는 소릴!","JPN":"な、何を言ってるんですか！","ENG":"O-of course not! That's ridiculous!","TWN":"您、您說什麼荒唐的事情呢！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"저희 관리부는 항상 정보 취급에 만전을 기하고 있습니다!","JPN":"管理部は情報の取り扱いには十分注意を払っているんです！","ENG":"The Managerial Department always makes sure to keep all information secured!","TWN":"我們管理部對情報管理是很嚴格的！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런 사사로운 거래로 정보가 유출되는 일은 결코 없습니다.","JPN":"そのような私的な事で情報が流出することは、決してありません。","ENG":"There is no way that any information could be leaked for such a petty deal.","TWN":"絕對不會因為那種私下交易洩露的！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......이, 있다고 해도 기억나지 않습니다!","JPN":"……も、もしあったとしても、記憶にございません！","ENG":"A-and even if there is, I don't remember!","TWN":"……就算有，我也不記得了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"네......?","JPN":"はい……？","ENG":"Huh?","TWN":"什麼……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런데 왜 주시윤 군에게 이상형에 대한 상세 정보를 메일로 보냈냐고요?","JPN":"どうしてアキヤマ・シリュウに、理想のタイプに関する詳細情報をメールで送ったのか、ですか？","ENG":"Why did I send an email to Shiyoon describing my ideal man?","TWN":"那為什麼會給周時雲君發送理想類型的詳細情報？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그, 그거야 개인 사정이죠! 개인 사정!","JPN":"そ、それは！　こっ、個人的な事情です！","ENG":"Th-that's personal! Completely personal!","TWN":"那、那是我個人的事情！個人的事情！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"거기에 대해서는 더이상 노코멘트 하겠습니다.","JPN":"それについては、これ以上お答えするつもりはありません。","ENG":"I have nothing else to say about that.","TWN":"關於這件事我無可奉告。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"크흠! 크흠......!","JPN":"コホン！　コホン……！","ENG":"Ahem! Ahem!","TWN":"咳咳！咳咳……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"어쨌거나 알고 싶으신 게...... 주시윤 군의 첫 입사 기록이라고 하셨죠?","JPN":"とにかく、お知りになりたいのは……アキヤマ君の入社初期の記録でしたよね？","ENG":"Anyway, you were looking for... Joo Shiyoon's records of when he first joined the company?","TWN":"總之，您說您想知道…… 周時雲君的最初入職記錄嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 여기에 있네요.","JPN":"あぁ、こちらにありますね。","ENG":"Ah, here they are.","TWN":"好的，在這裡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"주시윤, 12세. 보호근로 대상. 작전부 견습.","JPN":"アキヤマ・シリュウ、12歳。労働保護対象。作戦部研修。","ENG":"Joo Shiyoon, age 12. Subject to labor protection. A trainee at the Operation Department.","TWN":"周時雲，12歲。勞動保護對象。作戰部見習隊員。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......그러고 보니 그때도 깜짝 놀랐었죠.","JPN":"……そういえば、とても驚いたのを覚えています。","ENG":"Actually, I was really surprised back then.","TWN":"……這麼說來，當時我也是嚇了一跳。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그 호랑이 같은 소대장님이 웬 꼬맹이를 데리고 회사에 출근했으니까요.","JPN":"あの虎のような小隊長が、子どもを連れて出社したものですから。","ENG":"Because that fearsome commander brought a kid to work.","TWN":"那個像老虎一樣的小隊長居然帶著一個小不點來公司上班。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그...... 힐데 소대장님이 외모는 그래도 나이는 많다고 하잖아요?","JPN":"ほら……、ヒルデ小隊長はああ見えて、結構年を重ねているそうじゃないですか？","ENG":"You know, Commander Hilde is actually a lot older than she looks.","TWN":"那個……不是說希爾德小隊長的年齡比看起來還要年長嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래서 처음에는 어디 숨겨 놓은 자식인가 하는 생각을.......","JPN":"だから、最初見た時は隠し子だとばかり……","ENG":"So at first I thought Shiyoon was her secret son...","TWN":"所以起初，我還以為是偷偷藏在哪裡的小孩……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 하하하! 그, 그럴 리가 없겠죠. 그럴 리가.......","JPN":"あ、ははは！　そ、そんなはずはないんですけどね……","ENG":"Ah hah hah! O-of course that couldn't be true. That couldn't be...","TWN":"啊，哈哈哈！怎麼會有這種事呢，怎麼可能……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"생각해 보면...... 친인척이라고 하기엔 사이도 딱히 좋아 보이지 않았고.......","JPN":"今思えば……、家族というほど仲が良さそうでもなかったですし……","ENG":"Come to think of it, they didn't seem to be very close to each other to be relatives...","TWN":"仔細想想……說是親戚關係，關係好像也沒那麼好……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"사제관계라고 보기에도 데면데면했어요.","JPN":"師弟関係というにも、よそよそしかったですね。","ENG":"And they were too indifferent to each other to be considered a Master and a apprentice.","TWN":"說是師生關係，也有點勉強。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......특이한 점이요?","JPN":"……変わったところですか？","ENG":"Did I notice anything special?","TWN":"……您說他有些特別的地方？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"음....... 요즘 들어온 사람은 잘 모르겠지만.......","JPN":"うーん……最近入った人は知らないでしょうけど……","ENG":"Hmm, people who have joined us recently probably don't know this...","TWN":"嗯……最近進公司的人都不是很清楚，但是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"사실 시윤 군이 처음부터 저런 성격은 아니었거든요.","JPN":"実はアキヤマ君って、最初からあんな性格ではなかったんです。","ENG":"But Shiyoon wasn't like that from the beginning.","TWN":"其實周時雲君一開始不是那種性格的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"처음 회사에 왔을 때는 말수도 별로 없고, 수줍음도 많이 타고.......","JPN":"会社に来た当初は無口で、恥ずかしがり屋で……","ENG":"When he first came here, he was very quiet and shy.","TWN":"他剛來公司的時候也不怎麼說話，而且很害羞。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"오히려 어두운 편이었어요.","JPN":"むしろ暗い子でした。","ENG":"He was rather gloomy.","TWN":"甚至可以說是有點陰沉。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"사내 직원들 사이에서 저러다가 어느 날 갑자기 아무도 모르게 사라질지도 모른다는 이야기도 돌았었는데.......","JPN":"職員たちの間でも、あれじゃいついなくなっても誰も気づかないんじゃないかって言われるくらい存在感が薄い子でしたから。","ENG":"There was a rumor among the employees that he might suddenly disappear without anyone knowing.","TWN":"公司裡的員工常說他要是繼續這樣，哪天就算消失了也沒人會發現。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"뭐, 지금은 너무 활달한 성격으로 바뀌어서 문제이긴 하죠...... 하하.","JPN":"でも、今はその逆で活発すぎて問題です……はは。","ENG":"Well, he's become a little too bright nowadays... Hah hah.","TWN":"不過，他現在變得太過開朗，反而是個問題呢……哈哈。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 이건 그냥 개인적인 착각일 수도 있지만요.......","JPN":"あ、これは私の思い違いかもしれませんが。","ENG":"Oh, and I might be imagining things...","TWN":"啊，雖然這可能只是我個人的錯覺……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"가끔은......","JPN":"時々……","ENG":"But sometimes...","TWN":"但有時候……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"어쩐지 일부러 무리하고 있는 게 아닐까 하는 생각이 들기도 해요.......","JPN":"わざと無理してるんじゃないかって、思う時があるんです……","ENG":"I feel like he's deliberately pretending to be cheerful.","TWN":"總覺得他是不是在故意勉強……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};